import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'app_colors.dart';import 'app_spacing.dart';class DsToggleSwitch extends StatefulWidget {  final bool value;  final ValueChanged<bool> onChanged;  const DsToggleSwitch({    super.key,    required this.value,    required this.onChanged,  });  @override  State<DsToggleSwitch> createState() => _DsToggleSwitchState();}@overrideclass _DsToggleSwitchState extends State<DsToggleSwitch> with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<Alignment> _alignAnimation;  late Animation<Color?> _colorAnimation;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 180),      value: widget.value ? 1.0 : 0.0,    );    _alignAnimation = AlignmentTween(      begin: Alignment.centerLeft,      end: Alignment.centerRight,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeIn),    );    _colorAnimation = ColorTween(      begin: AppColors.toggleTrackOff,      end: AppColors.primary,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeIn),    );  }  @override  void didUpdateWidget(covariant DsToggleSwitch oldWidget) {    super.didUpdateWidget(oldWidget);    if (oldWidget.value != widget.value) {      if (widget.value) {        _controller.forward();      } else {        _controller.reverse();      }    }  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _handleTap() {    HapticFeedback.lightImpact();    widget.onChanged(!widget.value);  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTap: _handleTap,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Container(            width: AppSpacing.toggleWidth,            height: AppSpacing.toggleHeight,            padding: const EdgeInsets.all(2.0),            decoration: BoxDecoration(              color: _colorAnimation.value,              borderRadius: BorderRadius.circular(AppSpacing.borderRadiusLarge),              boxShadow: [                if (widget.value)                  BoxShadow(                    color: AppColors.primary.withOpacity(0.3),                    blurRadius: 8,                    spreadRadius: 1,                  ),              ],            ),            child: Align(              alignment: _alignAnimation.value,              child: Container(                width: AppSpacing.toggleHeight - 4, // Thumb size                height: AppSpacing.toggleHeight - 4,                decoration: const BoxDecoration(                  color: AppColors.toggleThumb,                  shape: BoxShape.circle,                ),              ),            ),          );        },      ),    );  }}